// Chat.jsx - Domain tags that add to input like "domain:santé"
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import s from './Chat.module.css';

const T = {
  fr: {
    newChat: 'Nouveau chat', today: "Aujourd'hui", days30: '30 derniers jours',
    settings: 'Paramètres', signOut: 'Déconnexion',
    welcomeTitle: 'Bienvenue sur AI Advisor',
    welcomeSub: 'Votre assistant intelligent pour la performance des campagnes, la qualité des utilisateurs et les décisions de croissance.',
    examples: 'Exemples', capabilities: 'Capacités', limitations: 'Limites',
    ex1: 'Quelle campagne a eu le meilleur ROI ces 30 derniers jours ?',
    ex2: 'Comparez la rétention entre iOS et Android en Europe',
    ex3: 'Quels segments d\'audience chutent après le jour 7 ?',
    cap1: 'Analyser les tendances de performance des campagnes',
    cap2: 'Recommander des réallocations budgétaires',
    cap3: 'Prévoir LTV, rétention et ROAS',
    lim1: 'Les données doivent être disponibles dans votre tableau de bord',
    lim2: 'Les suggestions IA sont basées sur vos données',
    lim3: 'Toujours revoir les recommandations avant application',
    placeholder: 'Demandez tout ce qui concerne vos campagnes...',
    hint: 'Entrée pour envoyer · Shift+Entrée pour nouvelle ligne',
    theme: 'Thème', light: 'Clair', dark: 'Sombre', language: 'Langue',
    domains: 'Domaines',
    domainSante: 'santé',
    domainEducation: 'éducation',
    domainTech: 'technologie',
    domainBusiness: 'business',
    domainLegal: 'juridique',
    domainMarketing: 'marketing',
    userPrefix: 'user:',
    domainPrefix: 'domain:',
  },
  en: {
    newChat: 'New chat', today: 'Today', days30: '30 days',
    settings: 'Settings', signOut: 'Sign out',
    welcomeTitle: 'Welcome to AI Advisor',
    welcomeSub: 'Your smart assistant for campaign performance, user quality, and growth decisions.',
    examples: 'Examples', capabilities: 'Capabilities', limitations: 'Limitations',
    ex1: 'Which campaign had the best ROI in the last 30 days?',
    ex2: 'Compare retention across iOS and Android in Europe',
    ex3: 'Which audience segments are dropping after Day 7?',
    cap1: 'Analyze campaign performance trends across KPIs',
    cap2: 'Recommend budget reallocations and targeting changes',
    cap3: 'Forecast LTV, retention, and ROAS for specific segments',
    lim1: 'Data must be available in your dashboard for analysis',
    lim2: 'AI suggestions are based on your data, not external sources',
    lim3: 'Always review automated recommendations before applying',
    placeholder: 'Ask anything about your campaigns, users, or performance...',
    hint: 'Enter to send · Shift+Enter for new line',
    theme: 'Theme', light: 'Light', dark: 'Dark', language: 'Language',
    domains: 'Domains',
    domainSante: 'health',
    domainEducation: 'education',
    domainTech: 'technology',
    domainBusiness: 'business',
    domainLegal: 'legal',
    domainMarketing: 'marketing',
    userPrefix: 'user:',
    domainPrefix: 'domain:',
  },
  ar: {
    newChat: 'محادثة جديدة', today: 'اليوم', days30: 'آخر 30 يومًا',
    settings: 'الإعدادات', signOut: 'تسجيل الخروج',
    welcomeTitle: 'مرحبًا بك في المستشار الذكي',
    welcomeSub: 'مساعدك الذكي لأداء الحملات وجودة المستخدمين وقرارات النمو.',
    examples: 'أمثلة', capabilities: 'القدرات', limitations: 'القيود',
    ex1: 'ما هي الحملة التي حققت أفضل عائد على الاستثمار في آخر 30 يومًا؟',
    ex2: 'قارن الاحتفاظ بين iOS و Android في أوروبا',
    ex3: 'ما هي شرائح الجمهور التي تنخفض بعد اليوم السابع؟',
    cap1: 'تحليل اتجاهات أداء الحملة عبر مؤشرات الأداء',
    cap2: 'توصية بإعادة تخصيص الميزانية وتغييرات الاستهداف',
    cap3: 'التنبؤ بـ LTV والاحتفاظ و ROAS لشرائح محددة',
    lim1: 'يجب أن تكون البيانات متاحة في لوحة التحكم للتحليل',
    lim2: 'تعتمد اقتراحات الذكاء الاصطناعي على بياناتك',
    lim3: 'راجع دائمًا التوصيات الآلية قبل التطبيق',
    placeholder: 'اسأل أي شيء عن حملاتك أو مستخدميك أو أدائك...',
    hint: 'Enter للإرسال · Shift+Enter لسطر جديد',
    theme: 'المظهر', light: 'فاتح', dark: 'داكن', language: 'اللغة',
    domains: 'المجالات',
    domainSante: 'الصحة',
    domainEducation: 'التعليم',
    domainTech: 'التكنولوجيا',
    domainBusiness: 'الأعمال',
    domainLegal: 'قانوني',
    domainMarketing: 'تسويق',
    userPrefix: 'المستخدم:',
    domainPrefix: 'المجال:',
  },
};

// Domain tags configuration
const DOMAIN_TAGS = [
  { id: 'sante', labelKey: 'domainSante', prefix: 'domain:', value: 'sante', icon: '🏥' },
  { id: 'education', labelKey: 'domainEducation', prefix: 'domain:', value: 'education', icon: '📚' },
  { id: 'tech', labelKey: 'domainTech', prefix: 'domain:', value: 'tech', icon: '💻' },
  { id: 'business', labelKey: 'domainBusiness', prefix: 'domain:', value: 'business', icon: '📊' },
  { id: 'legal', labelKey: 'domainLegal', prefix: 'domain:', value: 'legal', icon: '⚖️' },
  { id: 'marketing', labelKey: 'domainMarketing', prefix: 'domain:', value: 'marketing', icon: '📢' },
];

// User tags examples
const USER_TAGS = [
  { id: 'azelmad', value: 'azelmad', icon: '👤' },
  { id: 'fatima', value: 'fatima', icon: '👤' },
  { id: 'youssef', value: 'youssef', icon: '👤' },
  { id: 'amina', value: 'amina', icon: '👤' },
];

export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();
  const [language, setLanguage] = useState('fr');
  const [showSettings, setShowSettings] = useState(false);
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);
  const t = T[language];

  const examples = [t.ex1, t.ex2, t.ex3];
  const capabilities = [t.cap1, t.cap2, t.cap3];
  const limitations = [t.lim1, t.lim2, t.lim3];

  // Add tag to input
  const addTagToInput = (tagText) => {
    const currentInput = input;
    const newInput = currentInput + (currentInput ? ' ' : '') + tagText + ' ';
    setInput(newInput);
    textareaRef.current?.focus();
  };

  // Add domain tag
  const addDomainTag = (domain) => {
    const tag = `${t.domainPrefix}${domain.value}`;
    addTagToInput(tag);
  };

  // Add user tag
  const addUserTag = (userName) => {
    const tag = `${t.userPrefix}${userName.value}`;
    addTagToInput(tag);
  };

  useEffect(() => {
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  useEffect(() => { loadConversations(); }, []);
  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const loadConversations = async () => {
    try {
      const r = await axios.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch {}
  };

  const loadConversation = async (convId) => {
    try {
      const r = await axios.get(`/conversations/${convId}/messages`);
      setMessages(r.data.messages.map(m => ({ role: m.sender === 'user' ? 'user' : 'bot', content: m.content })));
      setActiveConvId(convId);
    } catch {}
  };

  const deleteConversation = async (id, e) => {
    e.stopPropagation();
    try {
      await axios.delete(`/conversations/${id}`);
      setConversations(prev => prev.filter(c => c.id !== id));
      if (activeConvId === id) { setActiveConvId(null); setMessages([]); }
    } catch {}
  };

  const newConversation = () => { 
    setActiveConvId(null); 
    setMessages([]);
    textareaRef.current?.focus(); 
  };

  const handleInputChange = e => {
    setInput(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 200) + 'px';
  };

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      sendMessage(); 
    }
  };

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;

    setMessages(prev => [...prev, { role: 'user', content: text }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);

    try {
      const r = await axios.post('/chat', { 
        message: text, 
        conversation_id: activeConvId 
      });
      setMessages(prev => [...prev, { role: 'bot', content: r.data.response }]);
      if (!activeConvId && r.data.conversation_id) { 
        setActiveConvId(r.data.conversation_id); 
        loadConversations();
      }
    } catch {
      setMessages(prev => [...prev, { role: 'bot', content: language === 'fr' ? 'Erreur de connexion. Veuillez réessayer.' : 'Connection error. Please try again.' }]);
    } finally { 
      setLoading(false);
    }
  };

  const now = new Date();
  const grouped = conversations.reduce((acc, c) => {
    const d = new Date(c.updated_at || c.created_at);
    const diff = (now - d) / 86400000;
    if (diff < 1) acc.today.push(c);
    else if (diff < 30) acc.days30.push(c);
    return acc;
  }, { today: [], days30: [] });

  return (
    <div className={s.layout}>
      {/* Settings Modal */}
      {showSettings && (
        <div className={s.modalOverlay} onClick={() => setShowSettings(false)}>
          <div className={s.modal} onClick={e => e.stopPropagation()}>
            <div className={s.modalHeader}>
              <h3>{t.settings}</h3>
              <button className={s.closeModal} onClick={() => setShowSettings(false)}>×</button>
            </div>
            <div className={s.modalBody}>
              <div className={s.settingItem}>
                <span>{t.language}</span>
                <div className={s.langOptions}>
                  {['fr','en','ar'].map(l => (
                    <button key={l} onClick={() => setLanguage(l)} className={`${s.langOptionBtn} ${language === l ? s.langOptionActive : ''}`}>
                      {l.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideHeader}>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            {t.newChat}
          </button>
        </div>
        <div className={s.sideContent}>
          {grouped.today.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.today}</div>
              {grouped.today.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
          {grouped.days30.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.days30}</div>
              {grouped.days30.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className={s.sideFooter}>
          <button className={s.userBtn} onClick={() => setShowSettings(true)}>
            <div className={s.userAvatar}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{user?.username || 'User'}</div>
              <div className={s.userEmail}>{user?.email || ''}</div>
            </div>
          </button>
          <button className={s.signOutBtn} onClick={() => { logout(); nav('/'); }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/>
            </svg>
            {t.signOut}
          </button>
        </div>
      </aside>

      {/* Main */}
      <main className={s.main}>
        <div className={s.mainHeader}>
          <div className={s.headerLeft}>
            <button className={s.menuBtn} onClick={() => setSidebarOpen(v => !v)}>☰</button>
            <div className={s.headerLogo}>
              <img src="/logo.png" alt="Logo" width={26} />
              <span>AWAL GPT</span>
            </div>
          </div>
          <div className={s.headerActions}>
            {['fr','en','ar'].map(l => (
              <button key={l} onClick={() => setLanguage(l)} className={`${s.langBtn} ${language === l ? s.langActive : ''}`}>
                {l.toUpperCase()}
              </button>
            ))}
            <button className={s.langBtn} onClick={() => setShowSettings(true)}>⚙️</button>
          </div>
        </div>

        <div className={s.messagesArea}>
          <div className={s.messages}>
            {messages.length === 0 ? (
              <div className={s.welcome}>
                <img src="/logo.png" alt="Logo" className={s.welcomeLogo} />
                <h1 className={s.welcomeTitle}>{t.welcomeTitle}</h1>
                <p className={s.welcomeSub}>{t.welcomeSub}</p>

                {/* Domain Tags Section */}
                <div className={s.tagsSection}>
                  <h4 className={s.tagsTitle}>🏷️ {t.domains}</h4>
                  <div className={s.tagsGrid}>
                    {DOMAIN_TAGS.map(domain => (
                      <button 
                        key={domain.id}
                        className={s.domainTag}
                        onClick={() => addDomainTag(domain)}
                      >
                        <span className={s.tagIcon}>{domain.icon}</span>
                        <span className={s.tagText}>{t[domain.labelKey]}</span>
                        <code className={s.tagCode}>{t.domainPrefix}{domain.value}</code>
                      </button>
                    ))}
                  </div>
                </div>

                {/* User Tags Section */}
                <div className={s.tagsSection}>
                  <h4 className={s.tagsTitle}>👤 user:nom</h4>
                  <div className={s.tagsGrid}>
                    {USER_TAGS.map(userTag => (
                      <button 
                        key={userTag.id}
                        className={s.userTag}
                        onClick={() => addUserTag(userTag)}
                      >
                        <span className={s.tagIcon}>{userTag.icon}</span>
                        <span className={s.tagText}>{userTag.value}</span>
                        <code className={s.tagCode}>{t.userPrefix}{userTag.value}</code>
                      </button>
                    ))}
                  </div>
                  <div className={s.customUserTag}>
                    <span>➕</span>
                    <input 
                      type="text" 
                      placeholder={t.userPrefix + "nom"}
                      className={s.customUserInput}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' && e.target.value.trim()) {
                          addTagToInput(`${t.userPrefix}${e.target.value.trim()}`);
                          e.target.value = '';
                        }
                      }}
                    />
                  </div>
                </div>

                {/* Examples Grid */}
                <div className={s.welcomeGrid}>
                  <div className={s.welcomeCard}>
                    <h4>{t.examples}</h4>
                    {examples.map((ex, i) => <p key={i} onClick={() => setInput(ex)}>{ex}</p>)}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.capabilities}</h4>
                    {capabilities.map((c, i) => <p key={i} className={s.capability}>{c}</p>)}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.limitations}</h4>
                    {limitations.map((l, i) => <p key={i} className={s.limitation}>{l}</p>)}
                  </div>
                </div>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div key={idx} className={s.message}>
                  <div className={s.messageAvatar}>
                    {msg.role === 'user'
                      ? <div className={s.userAvatarMsg}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
                      : <div className={s.botAvatar}><img src="/logo.png" alt="AI" width={20} /></div>
                    }
                  </div>
                  <div className={s.messageContent}>
                    <div className={s.messageName}>{msg.role === 'user' ? (user?.username || 'You') : 'AI Advisor'}</div>
                    <div className={s.messageText}>{msg.content}</div>
                  </div>
                </div>
              ))
            )}
            {loading && (
              <div className={s.message}>
                <div className={s.messageAvatar}><div className={s.botAvatar}><img src="/logo.png" alt="AI" width={20} /></div></div>
                <div className={s.messageContent}>
                  <div className={s.messageName}>AI Advisor</div>
                  <div className={s.typing}><span /><span /><span /></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        <div className={s.inputArea}>
          <div className={s.inputContainer}>
            <div className={s.inputBox}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                placeholder={t.placeholder}
                value={input}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={loading}
              />
              <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
            <div className={s.inputHint}>{t.hint}</div>
          </div>
        </div>
      </main>
    </div>
  );
}
